                flux_i_momentum_x += factor * (ff_flux_contribution_momentum_x[0].x + fc_momentum_x_x);
                flux_i_momentum_y += factor * (ff_flux_contribution_momentum_y[0].x + fc_momentum_y_x);
                flux_i_momentum_z += factor * (ff_flux_contribution_momentum_z[0].x + fc_momentum_z_x);

                factor = 0.5f * normal_y;
                flux_i_density += factor * (ff_variable[VAR_MOMENTUM + 1] + momentum_i_y);
                flux_i_density_energy += factor * (ff_flux_contribution_density_energy[0] + fc_density_energy_y);
                flux_i_momentum_x += factor * (ff_flux_contribution_momentum_x[0].y + fc_momentum_x_y);
                flux_i_momentum_y += factor * (ff_flux_contribution_momentum_y[0].y + fc_momentum_y_y);
                flux_i_momentum_z += factor * (ff_flux_contribution_momentum_z[0].y + fc_momentum_z_y);

                factor = 0.5f * normal_z;
                flux_i_density += factor * (ff_variable[VAR_MOMENTUM + 2] + momentum_i_z);
                flux_i_density_energy += factor * (ff_flux_contribution_density_energy[0] + fc_density_energy_z);
                flux_i_momentum_x += factor * (ff_flux_contribution_momentum_x[0].z + fc_momentum_x_z);
                flux_i_momentum_y += factor * (ff_flux_contribution_momentum_y[0].z + fc_momentum_y_z);
                flux_i_momentum_z += factor * (ff_flux_contribution_momentum_z[0].z + fc_momentum_z_z);
            }
        }

