                ori_row = row + in2_sub_cumh_sel2_rowlow - 1;
                ori_col = col + in2_sub_cumh_sel2_collow - 1;
                temp2 = d_in2_sub[ori_col * in2_sub_rows + ori_row];

                temp2 = temp - temp2;

                d_in2_sub2_sqr[col * in2_sub2_sqr_rows + row] = temp2 * temp2;

                d_conv[col * in2_sub2_sqr_rows + row] = d_conv[col * in2_sub2_sqr_rows + row] - temp2 * in_final_sum_local / in_mod_elem;
            }
        }

        for (col = 0; col < in2_pad_cols; col++) {
            for (row = 0; row < in2_pad_rows; row++) {
                if (row > (in2_pad_add_rows - 1) &&
                    row < (in2_pad_add_rows + in2_rows) &&
                    col > (in2_pad_add_cols - 1) &&
                    col < (in2_pad_add_cols + in2_cols)) {
                    ori_row = row - in2_pad_add_rows;
                    ori_col = col - in2_pad_add_cols;
                    d_in2_pad[col * in2_pad_rows + row] = d_in2_sqr[ori_col * in2_rows + ori_row];
                } else {
                    d_in2_pad[col * in2_pad_rows + row] = 0;
                }
            }
        }

        for (ei_new = 0; ei_new < in2_pad_cols; ei_new++) {
            pos_ori = ei_new * in2_pad_rows;
            sum = 0;
            for (position = pos_ori; position < pos_ori + in2_pad_rows; position = position + 1) {
                d_in2_pad[position] = d_in2_pad[position] + sum;
                sum = d_in2_pad[position];
            }
        }

        for (col = 0; col < in2_sub_cols; col++) {
            for (row = 0; row < in2_sub_rows; row++) {
                ori_row = row + in2_pad_cumv_sel_rowlow - 1;
                ori_col = col + in2_pad_cumv_sel_collow - 1;
                temp = d_in2_pad[ori_col * in2_pad_rows + ori_row];

                ori_row = row + in2_pad_cumv_sel2_rowlow - 1;
                ori_col = col + in2_pad_cumv_sel2_collow - 1;
                temp2 = d_in2_pad[ori_col * in2_pad_rows + ori_row];

                d_in2_sub[col * in2_sub_rows + row] = temp - temp2;
            }
        }

        for (ei_new = 0; ei_new < in2_sub_rows; ei_new++) {
            pos_ori = ei_new;
            sum = 0;
            for (position = pos_ori; position < pos_ori + in2_sub_elem; position = position + in2_sub_rows) {
                d_in2_sub[position] = d_in2_sub[position] + sum;
                sum = d_in2_sub[position];
            }
        }

        for (col = 0; col < conv_cols; col++) {
            for (row = 0; row < conv_rows; row++) {
                ori_row = row + in2_sub_cumh_sel_rowlow - 1;
                ori_col = col + in2_sub_cumh_sel_collow - 1;
                temp = d_in2_sub[ori_col * in2_sub_rows + ori_row];

                ori_row = row + in2_sub_cumh_sel2_rowlow - 1;
                ori_col = col + in2_sub_cumh_sel2_collow - 1;
                temp2 = d_in2_sub[ori_col * in2_sub_rows + ori_row];

                temp2 = temp - temp2;

                temp2 = temp2 - (d_in2_sub2_sqr[col * conv_rows + row] / in_mod_elem);

                if (temp2 < 0) {
                    temp2 = 0;
                }
                temp2 = sqrt(temp2);

                temp2 = denomT * temp2;

                d_conv[col * conv_rows + row] = d_conv[col * conv_rows + row] / temp2;
            }
        }

        cent = sSize + tSize + 1;
        pointer = frame_no - 1 + point_no * no_frames;
        tMask_row = cent + d_tRowLoc[pointer] - d_Row[point_no] - 1;
        tMask_col = cent + d_tColLoc[pointer] - d_Col[point_no] - 1;

        for (ei_new = 0; ei_new < tMask_elem; ei_new++) {
            d_tMask[ei_new] = 0;
        }
        d_tMask[tMask_col * tMask_rows + tMask_row] = 1;

        for (col = 1; col <= mask_conv_cols; col++) {
            j = col + mask_conv_joffset;
            jp1 = j + 1;
            if (mask_cols < jp1) {
                ja1 = jp1 - mask_cols;
            } else {
                ja1 = 1;
            }
            if (tMask_cols < j) {
                ja2 = tMask_cols;
            } else {
                ja2 = j;
            }

            for (row = 1; row <= mask_conv_rows; row++) {
                i = row + mask_conv_ioffset;
                ip1 = i + 1;

                if (mask_rows < ip1) {
                    ia1 = ip1 - mask_rows;
                } else {
                    ia1 = 1;
                }
                if (tMask_rows < i) {
                    ia2 = tMask_rows;
                } else {
                    ia2 = i;
                }

                s = 0;

                for (ja = ja1; ja <= ja2; ja++) {
                    jb = jp1 - ja;
                    for (ia = ia1; ia <= ia2; ia++) {
                        ib = ip1 - ia;
                        s = s + d_tMask[tMask_rows * (ja - 1) + ia - 1] * 1;
                    }
                }

                d_mask_conv[(col - 1) * conv_rows + (row - 1)] = d_conv[(col - 1) * conv_rows + (row - 1)] * s;
            }
        }

        fin_max_val = 0;
        fin_max_coo = 0;
        for (i = 0; i < mask_conv_elem; i++) {
            if (d_mask_conv[i] > fin_max_val) {
                fin_max_val = d_mask_conv[i];
                fin_max_coo = i;
            }
        }

        largest_row = (fin_max_coo + 1) % mask_conv_rows - 1;
        largest_col = (fin_max_coo + 1) / mask_conv_rows;
        if ((fin_max_coo + 1) % mask_conv_rows == 0) {
            largest_row = mask_conv_rows - 1;
            largest_col = largest_col - 1;
        }

        largest_row = largest_row + 1;
        largest_col = largest_col + 1;
        offset_row = largest_row - in_mod_rows - (sSize - tSize);
        offset_col = largest_col - in_mod_cols - (sSize - tSize);
        pointer = point_no * no_frames + frame_no;
        d_tRowLoc[pointer] = d_Row[point_no] + offset_row;
        d_tColLoc[pointer] = d_Col[point_no] + offset_col;
    }

    if (frame_no != 0 && (frame_no) % 10 == 0) {
        loc_pointer = point_no * no_frames + frame_no;
        d_Row[point_no] = d_tRowLoc[loc_pointer];
        d_Col[point_no] = d_tColLoc[loc_pointer];

        d_in = &d_T[point_no * in_mod_elem];

        for (col = 0; col < in_mod_cols; col++) {
            for (row = 0; row < in_mod_rows; row++) {
                ori_row = d_Row[point_no] - 25 + row - 1;
                ori_col = d_Col[point_no] - 25 + col - 1;
                ori_pointer = ori_col * frame_rows + ori_row;
                d_in[col * in_mod_rows + row] = alpha * d_in[col * in_mod_rows + row] + (1.00 - alpha) * d_frame[ori_pointer];
            }
        }
    }

    free(d_in2);
    free(d_in2_sqr);
    free(d_in_mod);
    free(d_in_sqr);
    free(d_conv);
    free(d_in2_pad);
    free(d_in2_sub);
    free(d_in2_sub2_sqr);
    free(d_tMask);
    free(d_mask_conv);
}

#define fp float

#define ENDO_POINTS 20
#define EPI_POINTS 31
#define ALL_POINTS 51

kernel void heartwall_kernel(params_common public,
                             int* endoRow,
                             int* endoCol,
                             int* tEndoRowLoc,
                             int* tEndoColLoc,
                             int* epiRow,
                             int* epiCol,
                             int* tEpiRowLoc,
                             int* tEpiColLoc,
                             fp* endoT,
                             fp* epiT,
                             fp* d_frame,
                             fp* d_in2,
                             fp* d_in2_sqr,
                             fp* d_in_mod,
                             fp* d_in_sqr,
                             fp* d_conv,
                             fp* d_in2_pad,
                             fp* d_in2_sub,
                             fp* d_in2_sub2_sqr,
                             fp* d_tMask,
                             fp* d_mask_conv,
                             int frame_no)
{
    int point_no = get_global_id(0);

    if(point_no >= ALL_POINTS) return;

    int is_endo = (point_no < ENDO_POINTS);

    int* d_Row = is_endo ? endoRow : epiRow;
    int* d_Col = is_endo ? endoCol : epiCol;
    int* d_tRowLoc = is_endo ? tEndoRowLoc : tEpiRowLoc;
    int* d_tColLoc = is_endo ? tEndoColLoc : tEpiColLoc;
    fp* d_T = is_endo ? endoT : epiT;

    fp* d_in = &d_T[point_no * public.in_elem];

    int ei_new;
    int rot_row;
    int rot_col;
    int in2_rowlow;
    int in2_collow;
    int ic;
    int jc;
    int jp1;
    int ja1, ja2;
    int ip1;
    int ia1, ia2;
    int ja, jb;
    int ia, ib;
    fp s;
    int i;
    int j;
    int row;
    int col;
    int ori_row;
    int ori_col;
    int position;
    fp sum;
    int pos_ori;
    fp temp;
    fp temp2;
    int location;
    int cent;
    int tMask_row; 
    int tMask_col;
    fp largest_value_current = 0;
    fp largest_value = 0;
    int largest_coordinate_current = 0;
    int largest_coordinate = 0;
    fp fin_max_val = 0;
    int fin_max_coo = 0;
    int largest_row;
    int largest_col;
    int offset_row;
    int offset_col;
    fp in_final_sum;
    fp in_sqr_final_sum;
    fp mean;
    fp mean_sqr;
    fp variance;
    fp deviation;
    fp denomT;
    int pointer;
    int ori_pointer;
    int loc_pointer;
    int ei_mod;

    if(frame_no == 0){
        pointer = point_no * public.no_frames + frame_no;
        d_tRowLoc[pointer] = d_Row[point_no];
        d_tColLoc[pointer] = d_Col[point_no];

        d_in = &d_T[point_no * public.in_elem];

        for(col=0; col<public.in_cols; col++){
            for(row=0; row<public.in_rows; row++){
                ori_row = d_Row[point_no] - 25 + row - 1;
                ori_col = d_Col[point_no] - 25 + col - 1;
                ori_pointer = ori_col * public.frame_rows + ori_row;

                d_in[col * public.in_rows + row] = d_frame[ori_pointer];
            }
        }
    }

    if(frame_no != 0){
        in2_rowlow = d_Row[point_no] - public.sSize;
        in2_collow = d_Col[point_no] - public.sSize;

        for(col=0; col<public.in2_cols; col++){
            for(row=0; row<public.in2_rows; row++){
                ori_row = row + in2_rowlow - 1;
                ori_col = col + in2_collow - 1;
                temp = d_frame[ori_col * public.frame_rows + ori_row];
                d_in2[point_no * public.in2_elem + col * public.in2_rows + row] = temp;
                d_in2_sqr[point_no * public.in2_elem + col * public.in2_rows + row] = temp * temp;
            }
        }

        d_in = &d_T[point_no * public.in_elem];

        for(col=0; col<public.in_cols; col++){
            for(row=0; row<public.in_rows; row++){
                rot_row = (public.in_rows - 1) - row;
                rot_col = (public.in_rows - 1) - col;
                pointer = rot_col * public.in_rows + rot_row;

                temp = d_in[pointer];
                d_in_mod[point_no * public.in_elem + col * public.in_rows + row] = temp;
                d_in_sqr[point_no * public.in_elem + pointer] = temp * temp;
            }
        }

        in_final_sum = 0;
        for(i = 0; i < public.in_elem; i++){
            in_final_sum = in_final_sum + d_in[i];
        }

        in_sqr_final_sum = 0;
        for(i = 0; i < public.in_elem; i++){
            in_sqr_final_sum = in_sqr_final_sum + d_in_sqr[point_no * public.in_elem + i];
        }

        mean = in_final_sum / public.in_elem;
        mean_sqr = mean * mean;
        variance = (in_sqr_final_sum / public.in_elem) - mean_sqr;
        deviation = sqrt(variance);

        denomT = sqrt((fp)(public.in_elem - 1)) * deviation;

        for(col=1; col <= public.conv_cols; col++){
            j = col + public.joffset;
            jp1 = j + 1;
            if(public.in2_cols < jp1){
                ja1 = jp1 - public.in2_cols;
            }
            else{
                ja1 = 1;
            }
            if(public.in_cols < j){
                ja2 = public.in_cols;
            }
            else{
                ja2 = j;
            }

            for(row=1; row <= public.conv_rows; row++){
                i = row + public.ioffset;
                ip1 = i + 1;

                if(public.in2_rows < ip1){
                    ia1 = ip1 - public.in2_rows;
                }
                else{
                    ia1 = 1;
                }
                if(public.in_rows < i){
                    ia2 = public.in_rows;
                }
                else{
                    ia2 = i;
                }

                s = 0;

                for(ja=ja1; ja <= ja2; ja++){
                    jb = jp1 - ja;
                    for(ia=ia1; ia <= ia2; ia++){
                        ib = ip1 - ia;
                        s = s + d_in_mod[point_no * public.in_elem + public.in_rows * (ja - 1) + ia - 1] * 
                              d_in2[point_no * public.in2_elem + public.in2_rows * (jb - 1) + ib - 1];
                    }
                }

                d_conv[point_no * public.conv_elem + (col - 1) * public.conv_rows + (row - 1)] = s;
            }
        }

        for(col=0; col < public.in2_pad_cols; col++){
            for(row=0; row < public.in2_pad_rows; row++){
                if(row > (public.in2_pad_add_rows - 1) &&
                   row < (public.in2_pad_add_rows + public.in2_rows) &&
                   col > (public.in2_pad_add_cols - 1) &&
                   col < (public.in2_pad_add_cols + public.in2_cols)){
                    ori_row = row - public.in2_pad_add_rows;
                    ori_col = col - public.in2_pad_add_cols;
                    d_in2_pad[point_no * public.in2_pad_elem + col * public.in2_pad_rows + row] = 
                        d_in2[point_no * public.in2_elem + ori_col * public.in2_rows + ori_row];
                }
                else{
                    d_in2_pad[point_no * public.in2_pad_elem + col * public.in2_pad_rows + row] = 0;
                }
            }
        }

        for(ei_new = 0; ei_new < public.in2_pad_cols; ei_new++){
            pos_ori = ei_new * public.in2_pad_rows;

            sum = 0;
            for(position = pos_ori; position < pos_ori + public.in2_pad_rows; position = position + 1){
                d_in2_pad[point_no * public.in2_pad_elem + position] = d_in2_pad[point_no * public.in2_pad_elem + position] + sum;
                sum = d_in2_pad[point_no * public.in2_pad_elem + position];
            }
        }

        for(col=0; col < public.in2_sub_cols; col++){
            for(row=0; row < public.in2_sub_rows; row++){
                ori_row = row + public.in2_pad_cumv_sel_rowlow - 1;
                ori_col = col + public.in2_pad_cumv_sel_collow - 1;
                temp = d_in2_pad[point_no * public.in2_pad_elem + ori_col * public.in2_pad_rows + ori_row];

                ori_row = row + public.in2_pad_cumv_sel2_rowlow - 1;
                ori_col = col + public.in2_pad_cumv_sel2_collow - 1;
                temp2 = d_in2_pad[point_no * public.in2_pad_elem + ori_col * public.in2_pad_rows + ori_row];

                d_in2_sub[point_no * public.in2_sub_elem + col * public.in2_sub_rows + row] = temp - temp2;
            }
        }

        for(ei_new = 0; ei_new < public.in2_sub_rows; ei_new++){
            pos_ori = ei_new;

            sum = 0;
            for(position = pos_ori; position < pos_ori + public.in2_sub_elem; position = position + public.in2_sub_rows){
                d_in2_sub[point_no * public.in2_sub_elem + position] = d_in2_sub[point_no * public.in2_sub_elem + position] + sum;
                sum = d_in2_sub[point_no * public.in2_sub_elem + position];
            }
        }

        for(col=0; col < public.in2_sub2_cols; col++){
            for(row=0; row < public.in2_sub2_rows; row++){
                ori_row = row + public.in2_sub_cumh_sel_rowlow - 1;
                ori_col = col + public.in2_sub_cumh_sel_collow - 1;
                temp = d_in2_sub[point_no * public.in2_sub_elem + ori_col * public.in2_sub_rows + ori_row];

                ori_row = row + public.in2_sub_cumh_sel2_rowlow - 1;
                ori_col = col + public.in2_sub_cumh_sel2_collow - 1;
                temp2 = d_in2_sub[point_no * public.in2_sub_elem + ori_col * public.in2_sub_rows + ori_row];

                temp2 = temp - temp2;

                d_in2_sub2_sqr[point_no * public.in2_sub2_elem + col * public.in2_sub2_rows + row] = temp2 * temp2;

                d_conv[point_no * public.conv_elem + col * public.in2_sub2_rows + row] = 
                    d_conv[point_no * public.conv_elem + col * public.in2_sub2_rows + row] - 
                    temp2 * in_final_sum / public.in_elem;
            }
        }

        for(col=0; col < public.in2_pad_cols; col++){
            for(row=0; row < public.in2_pad_rows; row++){
                if(row > (public.in2_pad_add_rows - 1) &&
                   row < (public.in2_pad_add_rows + public.in2_rows) &&
                   col > (public.in2_pad_add_cols - 1) &&
                   col < (public.in2_pad_add_cols + public.in2_cols)){
                    ori_row = row - public.in2_pad_add_rows;
                    ori_col = col - public.in2_pad_add_cols;
                    d_in2_pad[point_no * public.in2_pad_elem + col * public.in2_pad_rows + row] = 
                        d_in2_sqr[point_no * public.in2_elem + ori_col * public.in2_rows + ori_row];
                }
                else{
                    d_in2_pad[point_no * public.in2_pad_elem + col * public.in2_pad_rows + row] = 0;
                }
            }
        }

        for(ei_new = 0; ei_new < public.in2_pad_cols; ei_new++){
            pos_ori = ei_new * public.in2_pad_rows;

            sum = 0;
            for(position = pos_ori; position < pos_ori + public.in2_pad_rows; position = position + 1){
                d_in2_pad[point_no * public.in2_pad_elem + position] = d_in2_pad[point_no * public.in2_pad_elem + position] + sum;
                sum = d_in2_pad[point_no * public.in2_pad_elem + position];
            }
        }

        for(col=0; col < public.in2_sub_cols; col++){
            for(row=0; row < public.in2_sub_rows; row++){
                ori_row = row + public.in2_pad_cumv_sel_rowlow - 1;
                ori_col = col + public.in2_pad_cumv_sel_collow - 1;
                temp = d_in2_pad[point_no * public.in2_pad_elem + ori_col * public.in2_pad_rows + ori_row];

                ori_row = row + public.in2_pad_cumv_sel2_rowlow - 1;
                ori_col = col + public.in2_pad_cumv_sel2_collow - 1;
                temp2 = d_in2_pad[point_no * public.in2_pad_elem + ori_col * public.in2_pad_rows + ori_row];

                d_in2_sub[point_no * public.in2_sub_elem + col * public.in2_sub_rows + row] = temp - temp2;
            }
        }

        for(ei_new = 0; ei_new < public.in2_sub_rows; ei_new++){
            pos_ori = ei_new;

            sum = 0;
            for(position = pos_ori; position < pos_ori + public.in2_sub_elem; position = position + public.in2_sub_rows){
                d_in2_sub[point_no * public.in2_sub_elem + position] = d_in2_sub[point_no * public.in2_sub_elem + position] + sum;
                sum = d_in2_sub[point_no * public.in2_sub_elem + position];
            }
        }

        for(col=0; col < public.conv_cols; col++){
            for(row=0; row < public.conv_rows; row++){
                ori_row = row + public.in2_sub_cumh_sel_rowlow - 1;
                ori_col = col + public.in2_sub_cumh_sel_collow - 1;
                temp = d_in2_sub[point_no * public.in2_sub_elem + ori_col * public.in2_sub_rows + ori_row];

                ori_row = row + public.in2_sub_cumh_sel2_rowlow - 1;
                ori_col = col + public.in2_sub_cumh_sel2_collow - 1;
                temp2 = d_in2_sub[point_no * public.in2_sub_elem + ori_col * public.in2_sub_rows + ori_row];

                temp2 = temp - temp2;

                temp2 = temp2 - (d_in2_sub2_sqr[point_no * public.in2_sub2_elem + col * public.conv_rows + row] / public.in_elem);

                if(temp2 < 0){
                    temp2 = 0;
                }
                temp2 = sqrt(temp2);

                temp2 = denomT * temp2;

                d_conv[point_no * public.conv_elem + col * public.conv_rows + row] = 
                    d_conv[point_no * public.conv_elem + col * public.conv_rows + row] / temp2;
            }
        }

        cent = public.sSize + public.tSize + 1;
        pointer = frame_no - 1 + point_no * public.no_frames;
        tMask_row = cent + d_tRowLoc[pointer] - d_Row[point_no] - 1;
        tMask_col = cent + d_tColLoc[pointer] - d_Col[point_no] - 1;

        for(ei_new = 0; ei_new < public.tMask_elem; ei_new++){
            d_tMask[point_no * public.tMask_elem + ei_new] = 0;
        }
        d_tMask[point_no * public.tMask_elem + tMask_col * public.tMask_rows + tMask_row] = 1;

        for(col=1; col <= public.mask_conv_cols; col++){
            j = col + public.mask_conv_joffset;
            jp1 = j + 1;
            if(public.mask_cols < jp1){
                ja1 = jp1 - public.mask_cols;
            }
            else{
                ja1 = 1;
            }
            if(public.tMask_cols < j){
                ja2 = public.tMask_cols;
            }
            else{
                ja2 = j;
            }

            for(row=1; row <= public.mask_conv_rows; row++){
                i = row + public.mask_conv_ioffset;
                ip1 = i + 1;

                if(public.mask_rows < ip1){
                    ia1 = ip1 - public.mask_rows;
                }
                else{
                    ia1 = 1;
                }
                if(public.tMask_rows < i){
                    ia2 = public.tMask_rows;
                }
                else{
                    ia2 = i;
                }

                s = 0;

                for(ja=ja1; ja <= ja2; ja++){
                    jb = jp1 - ja;
                    for(ia=ia1; ia <= ia2; ia++){
                        ib = ip1 - ia;
                        s = s + d_tMask[point_no * public.tMask_elem + public.tMask_rows * (ja - 1) + ia - 1] * 1;
                    }
                }

                d_mask_conv[point_no * public.mask_conv_elem + (col - 1) * public.conv_rows + (row - 1)] = 
                    d_conv[point_no * public.conv_elem + (col - 1) * public.conv_rows + (row - 1)] * s;
            }
        }

        fin_max_val = 0;
        fin_max_coo = 0;
        for(i=0; i < public.mask_conv_elem; i++){
            if(d_mask_conv[point_no * public.mask_conv_elem + i] > fin_max_val){
                fin_max_val = d_mask_conv[point_no * public.mask_conv_elem + i];
                fin_max_coo = i;
            }
        }

        largest_row = (fin_max_coo + 1) % public.mask_conv_rows - 1;
        largest_col = (fin_max_coo + 1) / public.mask_conv_rows;
        if((fin_max_coo + 1) % public.mask_conv_rows == 0){
            largest_row = public.mask_conv_rows - 1;
            largest_col = largest_col - 1;
        }

        largest_row = largest_row + 1;
        largest_col = largest_col + 1;
        offset_row = largest_row - public.in_rows - (public.sSize - public.tSize);
        offset_col = largest_col - public.in_cols - (public.sSize - public.tSize);
        pointer = point_no * public.no_frames + frame_no;
        d_tRowLoc[pointer] = d_Row[point_no] + offset_row;
        d_tColLoc[pointer] = d_Col[point_no] + offset_col;
    }

    if(frame_no != 0 && (frame_no % 10 == 0)){
        loc_pointer = point_no * public.no_frames + frame_no;
        d_Row[point_no] = d_tRowLoc[loc_pointer];
        d_Col[point_no] = d_tColLoc[loc_pointer];

        d_in = &d_T[point_no * public.in_elem];

        for(col=0; col < public.in_cols; col++){
            for(row=0; row < public.in_rows; row++){
                ori_row = d_Row[point_no] - 25 + row - 1;
                ori_col = d_Col[point_no] - 25 + col - 1;
                ori_pointer = ori_col * public.frame_rows + ori_row;

                d_in[col * public.in_rows + row] = public.alpha * d_in[col * public.in_rows + row] + 
                                                   (1.00 - public.alpha) * d_frame[ori_pointer];
            }
        }
    }
}

#define fp float

