// Euclidean distance squared between two points
float euclid_dist_2(float *pt1, float *pt2, int numdims) {
    float ans = 0.0f;
    for (int i = 0; i < numdims; i++) {
        float diff = pt1[i] - pt2[i];
        ans += diff * diff;
    }
    return ans;
}

// Find nearest cluster for a point
int find_nearest_point(float *pt, int nfeatures, float *clusters, int nclusters) {
    int index = 0;
    float min_dist = FLT_MAX;

    for (int i = 0; i < nclusters; i++) {
        float dist = euclid_dist_2(pt, clusters + i * nfeatures, nfeatures);
        if (dist < min_dist) {
            min_dist = dist;
            index = i;
        }
    }
    return index;
}

// Kernel to assign points to nearest clusters and accumulate sums
void kmeans_assign_kernel(
    const float *features,
    float *clusters,
    int *membership,
    int *cluster_counts,
    float *cluster_sums,
    int npoints,
    int nfeatures,
    int nclusters)
{
    int i = get_global_id(0);
    if (i >= npoints) return;

    // Find nearest cluster for this point
    int index = find_nearest_point(features + i * nfeatures, nfeatures, clusters, nclusters);

    // Update membership
    membership[i] = index;

    // Accumulate counts and sums for cluster center update
    cluster_counts[index]++;
    for (int j = 0; j < nfeatures; j++) {
        cluster_sums[index * nfeatures + j] += features[i * nfeatures + j];
    }
}

// Kernel to compute new cluster centers from accumulated sums
void kmeans_update_centers_kernel(
    float *clusters,
    int *cluster_counts,
    float *cluster_sums,
    int nclusters,
    int nfeatures)
{
    int i = get_global_id(0);
    if (i >= nclusters) return;

    if (cluster_counts[i] > 0) {
        for (int j = 0; j < nfeatures; j++) {
            clusters[i * nfeatures + j] = cluster_sums[i * nfeatures + j] / cluster_counts[i];
        }
    }
    // Reset for next iteration
    cluster_counts[i] = 0;
    for (int j = 0; j < nfeatures; j++) {
        cluster_sums[i * nfeatures + j] = 0.0f;
    }
}

// Kernel to compute delta (number of points that changed membership)
void kmeans_compute_delta_kernel(
    const int *old_membership,
    const int *new_membership,
    int *delta,
    int npoints)
{
    int i = get_global_id(0);
    if (i >= npoints) return;

    if (old_membership[i] != new_membership[i]) {
        (*delta)++;
    }
}

// Kernel to initialize cluster centers from random points
void kmeans_init_centers_kernel(
    float *clusters,
    const float *features,
    int *cluster_indices,
    int nclusters,
    int nfeatures)
{
    int i = get_global_id(0);
    if (i >= nclusters) return;

    int idx = cluster_indices[i];
    for (int j = 0; j < nfeatures; j++) {
        clusters[i * nfeatures + j] = features[idx * nfeatures + j];
    }
}

