    partial_new_centers[0] =(float**) malloc(nthreads*nclusters * sizeof(float*));
    for (i=1; i<nthreads; i++)
        partial_new_centers[i] = partial_new_centers[i-1] + nclusters;

    for (i=0; i<nthreads; i++)
    {
        for (j=0; j<nclusters; j++)
            partial_new_centers[i][j] = (float*)calloc(nfeatures, sizeof(float));
    }

    printf("num of threads = %d\n", nthreads);

    do {
        delta = 0.0;

        global float *feature_flat = (global float*)malloc(npoints * nfeatures * sizeof(float));
        global float *clusters_flat = (global float*)malloc(nclusters * nfeatures * sizeof(float));
        global int *membership_global = (global int*)malloc(npoints * sizeof(int));
        global int *partial_len_global = (global int*)malloc(nthreads * nclusters * sizeof(int));
        global float *partial_centers_global = (global float*)malloc(nthreads * nclusters * nfeatures * sizeof(float));
        global float *delta_global = (global float*)malloc(sizeof(float));

        for (i=0; i<npoints * nfeatures; i++)
            feature_flat[i] = feature[i / nfeatures][i % nfeatures];

        for (i=0; i<nclusters * nfeatures; i++)
            clusters_flat[i] = clusters[i / nfeatures][i % nfeatures];

        for (i=0; i<npoints; i++)
            membership_global[i] = membership[i];

        delta_global[0] = 0.0f;

        size_t global_size[2] = {npoints, nthreads};
        size_t local_size[2] = {1, 1};

        cl_kernel assign_kernel = clCreateKernel(program, "kmeans_assign_cluster");
        clSetKernelArg(assign_kernel, 0, sizeof(cl_mem), &feature_flat);
        clSetKernelArg(assign_kernel, 1, sizeof(cl_mem), &clusters_flat);
        clSetKernelArg(assign_kernel, 2, sizeof(cl_mem), &membership_global);
        clSetKernelArg(assign_kernel, 3, sizeof(cl_mem), &partial_len_global);
        clSetKernelArg(assign_kernel, 4, sizeof(cl_mem), &partial_centers_global);
        clSetKernelArg(assign_kernel, 5, sizeof(cl_mem), &delta_global);
        clSetKernelArg(assign_kernel, 6, sizeof(int), &npoints);
        clSetKernelArg(assign_kernel, 7, sizeof(int), &nclusters);
        clSetKernelArg(assign_kernel, 8, sizeof(int), &nfeatures);
        clSetKernelArg(assign_kernel, 9, sizeof(int), &nthreads);

        clEnqueueNDRangeKernel(queue, assign_kernel, 2, NULL, global_size, local_size);

        cl_kernel update_kernel = clCreateKernel(program, "kmeans_update_centers");
        clSetKernelArg(update_kernel, 0, sizeof(cl_mem), &clusters_flat);
        clSetKernelArg(update_kernel, 1, sizeof(cl_mem), &(float*)new_centers[0]);
        clSetKernelArg(update_kernel, 2, sizeof(cl_mem), &new_centers_len);
        clSetKernelArg(update_kernel, 3, sizeof(cl_mem), &partial_centers_global);
        clSetKernelArg(update_kernel, 4, sizeof(cl_mem), &partial_len_global);
        clSetKernelArg(update_kernel, 5, sizeof(int), &nclusters);
        clSetKernelArg(update_kernel, 6, sizeof(int), &nfeatures);
        clSetKernelArg(update_kernel, 7, sizeof(int), &nthreads);

        size_t update_global_size = nclusters;
        clEnqueueNDRangeKernel(queue, update_kernel, 1, NULL, &update_global_size, NULL);

        delta = delta_global[0];

        free(feature_flat);
        free(clusters_flat);
        free(membership_global);
        free(partial_len_global);
        free(partial_centers_global);
        free(delta_global);

    } while (delta > threshold && loop++ < 500);

    free(new_centers[0]);
    free(new_centers);
    free(new_centers_len);

    return clusters;
}

