#include <stdio.h>
#include <stdlib.h>
#include <string.h>
#include <math.h>
#include <float.h>
#include <CL/cl.h>

#ifndef FLT_MAX
#define FLT_MAX 3.40282347e+38
#endif

#ifndef RANDOM_MAX
#define RANDOM_MAX 2147483647
#endif

// OpenCL kernel source code
const char* kernel_source = 
"float euclid_dist_2(float* pt1, float* pt2, int numdims) {\n"
"    float ans = 0.0f;\n"
"    for (int i = 0; i < numdims; i++) {\n"
"        float diff = pt1[i] - pt2[i];\n"
"        ans += diff * diff;\n"
"    }\n"
"    return ans;\n"
"}\n"

"int find_nearest_point(float* pt, int nfeatures, float* clusters, int nclusters) {\n"
"    int index = 0;\n"
"    float min_dist = FLT_MAX;\n"
"    for (int i = 0; i < nclusters; i++) {\n"
"        float dist = euclid_dist_2(pt, clusters + i * nfeatures, nfeatures);\n"
"        if (dist < min_dist) {\n"
"            min_dist = dist;\n"
"            index = i;\n"
"        }\n"
"    }\n"
"    return index;\n"
"}\n"

"void kmeans_kernel(float* features, int nfeatures, int npoints,\n"
"                   float* clusters, int nclusters,\n"
"                   int* membership, int* centers_len, float* centers_sum) {\n"
"    int i = get_global_id(0);\n"
"    if (i < npoints) {\n"
"        int index = find_nearest_point(features + i * nfeatures, nfeatures, clusters, nclusters);\n"
"        membership[i] = index;\n"
"        centers_len[index]++;\n"
"        for (int j = 0; j < nfeatures; j++) {\n"
"            centers_sum[index * nfeatures + j] += features[i * nfeatures + j];\n"
"        }\n"
"    }\n"
"}\n";

// Helper function to create OpenCL context and queue
cl_context create_context(cl_platform_id* platform, cl_device_id* device, cl_command_queue* queue) {
    cl_uint num_platforms;
    cl_getPlatformIDs(0, NULL, &num_platforms);
    if (num_platforms == 0) return NULL;

    cl_getPlatformIDs(1, platform, NULL);

    cl_uint num_devices;
    cl_getDeviceIDs(platform[0], CL_DEVICE_TYPE_GPU, 0, NULL, &num_devices);
    if (num_devices == 0) {
        cl_getDeviceIDs(platform[0], CL_DEVICE_TYPE_CPU, 0, NULL, &num_devices);
    }
    if (num_devices == 0) return NULL;

    cl_getDeviceIDs(platform[0], CL_DEVICE_TYPE_GPU, 1, device, NULL);
    if (num_devices == 0) {
        cl_getDeviceIDs(platform[0], CL_DEVICE_TYPE_CPU, 1, device, NULL);
    }

    cl_context context = clCreateContext(NULL, 1, device, NULL, NULL, NULL);
    *queue = clCreateCommandQueue(context, device[0], 0, NULL);

    return context;
}

// Euclidean distance function (host version for initialization)
float euclid_dist_2(float *pt1, float *pt2, int numdims) {
    float ans = 0.0f;
    for (int i = 0; i < numdims; i++) {
        float diff = pt1[i] - pt2[i];
        ans += diff * diff;
    }
    return ans;
}

// Find nearest point (host version for initialization)
int find_nearest_point(float *pt, int nfeatures, float **pts, int npts) {
    int index = 0;
    float min_dist = FLT_MAX;
    for (int i = 0; i < npts; i++) {
        float dist = euclid_dist_2(pt, pts[i], nfeatures);
        if (dist < min_dist) {
            min_dist = dist;
            index = i;
        }
    }
    return index;
}

// Main kmeans clustering function with OpenCL
float** kmeans_clustering(float **feature, int nfeatures, int npoints,
                          int nclusters, float threshold, int *membership) {
    cl_platform_id platform;
    cl_device_id device;
    cl_command_queue queue;
    cl_context context = create_context(&platform, &device, &queue);
    if (context == NULL) {
        fprintf(stderr, "Failed to create OpenCL context\n");
        return NULL;
    }

    // Create program
    cl_program program = clCreateProgramWithSource(context, 1, &kernel_source, NULL, NULL);
    clBuildProgram(program, 1, &device, NULL, NULL, NULL);

    // Create kernel
    cl_kernel kernel = clCreateKernel(program, "kmeans_kernel", NULL);

    // Allocate OpenCL memory
    cl_mem features_mem = clCreateBuffer(context, CL_MEM_READ_ONLY | CL_MEM_COPY_HOST_PTR,
                                         npoints * nfeatures * sizeof(float), NULL, NULL);
    cl_mem clusters_mem = clCreateBuffer(context, CL_MEM_READ_WRITE,
                                         nclusters * nfeatures * sizeof(float), NULL, NULL);
    cl_mem membership_mem = clCreateBuffer(context, CL_MEM_WRITE_ONLY,
                                           npoints * sizeof(int), NULL, NULL);
    cl_mem centers_len_mem = clCreateBuffer(context, CL_MEM_READ_WRITE | CL_MEM_COPY_HOST_PTR,
                                            nclusters * sizeof(int), NULL, NULL);
    cl_mem centers_sum_mem = clCreateBuffer(context, CL_MEM_READ_WRITE | CL_MEM_COPY_HOST_PTR,
                                            nclusters * nfeatures * sizeof(float), NULL, NULL);

    // Set kernel arguments
    clSetKernelArg(kernel, 0, sizeof(cl_mem), &features_mem);
    clSetKernelArg(kernel, 1, sizeof(int), &nfeatures);
    clSetKernelArg(kernel, 2, sizeof(int), &npoints);
    clSetKernelArg(kernel, 3, sizeof(cl_mem), &clusters_mem);
    clSetKernelArg(kernel, 4, sizeof(int), &nclusters);
    clSetKernelArg(kernel, 5, sizeof(cl_mem), &membership_mem);
    clSetKernelArg(kernel, 6, sizeof(cl_mem), &centers_len_mem);
    clSetKernelArg(kernel, 7, sizeof(cl_mem), &centers_sum_mem);

    // Allocate host memory for clusters
    float **clusters = (float**) malloc(nclusters * sizeof(float*));
    clusters[0] = (float*) malloc(nclusters * nfeatures * sizeof(float));
    for (int i = 1; i < nclusters; i++)
        clusters[i] = clusters[i-1] + nfeatures;

    // Initialize clusters with first n points
    int n = 0;
    for (int i = 0; i < nclusters; i++) {
        for (int j = 0; j < nfeatures; j++)
            clusters[i][j] = feature[n][j];
        n++;
    }

    // Initialize membership
    for (int i = 0; i < npoints; i++)
        membership[i] = -1;

    // Allocate temporary arrays for cluster updates
    int *new_centers_len = (int*) calloc(nclusters, sizeof(int));
    float **new_centers = (float**) malloc(nclusters * sizeof(float*));
    new_centers[0] = (float*) calloc(nclusters * nfeatures, sizeof(float));
    for (int i = 1; i < nclusters; i++)
        new_centers[i] = new_centers[i-1] + nfeatures;

    // Write initial clusters to device
    clEnqueueWriteBuffer(queue, clusters_mem, CL_TRUE, 0,
                         nclusters * nfeatures * sizeof(float), clusters[0], NULL, NULL);

    int loop = 0;
    float delta;
    do {
        delta = 0.0f;

        // Reset centers_len and centers_sum on device
        int zero = 0;
        float zero_f = 0.0f;
        for (int i = 0; i < nclusters; i++) {
            clEnqueueWriteBuffer(queue, centers_len_mem, CL_FALSE,
                                 i * sizeof(int), sizeof(int), &zero, NULL, NULL);
            for (int j = 0; j < nfeatures; j++) {
                clEnqueueWriteBuffer(queue, centers_sum_mem, CL_FALSE,
                                     (i * nfeatures + j) * sizeof(float),
                                     sizeof(float), &zero_f, NULL, NULL);
            }
        }
        clFlush(queue);

        // Execute kernel
        size_t global_size = npoints;
        clEnqueueNativeKernel(queue, NULL, NULL, 0, NULL, NULL, 0, NULL, NULL);

        // Read membership back
        clEnqueueReadBuffer(queue, membership_mem, CL_TRUE, 0,
                            npoints * sizeof(int), membership, NULL, NULL);

        // Read centers_len and centers_sum
        clEnqueueReadBuffer(queue, centers_len_mem, CL_TRUE, 0,
                            nclusters * sizeof(int), new_centers_len, NULL, NULL);
        clEnqueueReadBuffer(queue, centers_sum_mem, CL_TRUE, 0,
                            nclusters * nfeatures * sizeof(float), new_centers[0], NULL, NULL);

        // Calculate delta and update clusters
        delta = 0.0f;
        for (int i = 0; i < npoints; i++) {
            int old_membership = membership[i];
            int new_index = find_nearest_point(feature[i], nfeatures, clusters, nclusters);
            if (old_membership != new_index) delta += 1.0f;
            membership[i] = new_index;
        }

        // Update cluster centers
        for (int i = 0; i < nclusters; i++) {
            for (int j = 0; j < nfeatures; j++) {
                if (new_centers_len[i] > 0)
                    clusters[i][j] = new_centers[i][j] / new_centers_len[i];
                new_centers[i][j] = 0.0f;
            }
            new_centers_len[i] = 0;
        }

        // Write updated clusters to device
        clEnqueueWriteBuffer(queue, clusters_mem, CL_TRUE, 0,
                             nclusters * nfeatures * sizeof(float), clusters[0], NULL, NULL);

        loop++;
    } while (delta > threshold && loop < 500);

    // Cleanup OpenCL resources
    clReleaseMemObject(features_mem);
    clReleaseMemObject(clusters_mem);
    clReleaseMemObject(membership_mem);
    clReleaseMemObject(centers_len_mem);
    clReleaseMemObject(centers_sum_mem);
    clReleaseKernel(kernel);
    clReleaseProgram(program);
    clReleaseCommandQueue(queue);
    clReleaseContext(context);

    // Cleanup host memory
    free(new_centers[0]);
    free(new_centers);
    free(new_centers_len);

    return clusters;
}

// Cluster function (main entry point)
int cluster(int numObjects, int numAttributes, float **attributes,
            int nclusters, float threshold, float ***cluster_centres) {
    int *membership = (int*) malloc(numObjects * sizeof(int));

    srand(7);

    float **tmp_cluster_centres = kmeans_clustering(attributes,
                                                    numAttributes,
                                                    numObjects,
                                                    nclusters,
                                                    threshold,
                                                    membership);

    if (*cluster_centres) {
        free((*cluster_centres)[0]);
        free(*cluster_centres);
    }
    *cluster_centres = tmp_cluster_centres;

    free(membership);

    return 0;
}

