__kernel void compute_kernel(int timeinst,
                             __global fp *initvalu,
                             __global fp *finavalu,
                             __global fp *parameter,
                             __global fp *com){

    int thread_id = get_global_id(0);

    if(thread_id == 0){
        ecc_kernel((fp)timeinst, initvalu, 0, parameter, 0, finavalu);
    }

    if(thread_id == 1){
        fp CaDyad = initvalu[35]*1e3;
        fp JCaDyad = cam_kernel((fp)timeinst, initvalu, 46, parameter, 1, finavalu, CaDyad);
        com[0] = JCaDyad;
    }

    if(thread_id == 2){
        fp CaSL = initvalu[36]*1e3;
        fp JCaSL = cam_kernel((fp)timeinst, initvalu, 61, parameter, 6, finavalu, CaSL);
        com[1] = JCaSL;
    }

    if(thread_id == 3){
        fp CaCyt = initvalu[37]*1e3;
        fp JCaCyt = cam_kernel((fp)timeinst, initvalu, 76, parameter, 11, finavalu, CaCyt);
        com[2] = JCaCyt;
    }
}

