__kernel void dynproc_kernel(
    int pyramid_height,
    __global const int* wall,
    __global const int* src_buffer,
    __global int* dst_buffer,
    int cols,
    int rows,
    int t_offset,
    int borderCols,
    int theHalo,
    __local int* local_src,
    __local int* local_dst,
    __global int* outputBuffer)
{
    int idx = get_global_id(0);

    if (idx >= cols) return;

    // Process pyramid_height rows
    for (int h = 0; h < pyramid_height; h++) {
        int row = t_offset + h;
        if (row >= rows - 1) break;

        int min = src_buffer[idx];

        // Check left neighbor
        if (idx > 0) {
            int left = src_buffer[idx - 1];
            if (left < min) min = left;
        }

        // Check right neighbor
        if (idx < cols - 1) {
            int right = src_buffer[idx + 1];
            if (right < min) min = right;
        }

        // Compute new value: wall[row][idx] + min
        dst_buffer[idx] = wall[row * cols + idx] + min;
    }
}

#define MIN(a, b) ((a)<=(b) ? (a) : (b))

kernel void dynproc_kernel(
    int num_steps,
    const int* wall_data,
    const int* src_buf,
    int* dst_buf,
    int cols,
    int rows,
    int row_offset,
    int borderCols,
    int halo,
    local int* local_src1,
    local int* local_src2,
    int* output_buffer
) {
    int n = (int)get_global_id(0);
    if (n >= cols) return;

    for (int s = 0; s < num_steps; s++) {
        int src_val;
        int left_val;
        int right_val;

        if (s == 0) {
            src_val = src_buf[n];
            if (n > 0) left_val = src_buf[n-1];
            if (n < cols - 1) right_val = src_buf[n+1];
        } else {
            src_val = dst_buf[n];
            if (n > 0) left_val = dst_buf[n-1];
            if (n < cols - 1) right_val = dst_buf[n+1];
        }

        int min_val = src_val;
        if (n > 0) {
            min_val = MIN(min_val, left_val);
        }
        if (n < cols - 1) {
            min_val = MIN(min_val, right_val);
        }

        int r = row_offset + s;
        int wall_val = wall_data[r * cols + n];

        dst_buf[n] = wall_val + min_val;
    }
}

__kernel void dynproc_kernel(
    int pyramid_height,
    __global int* wall,
    __global int* src_result,
    __global int* dst_result,
    int cols,
    int rows,
    int t,
    int borderCols,
    int theHalo,
    __local int* local_scratch1,
    __local int* local_scratch2,
    __global int* outputBuffer
)
{
    int n = get_global_id(0);

    if (n >= cols) return;

    int min = src_result[n];
    if (n > 0) {
        int left = src_result[n-1];
        min = min < left ? min : left;
    }
    if (n < cols-1) {
        int right = src_result[n+1];
        min = min < right ? min : right;
    }

    // wall is stored from row 1 onwards (data + cols in host code)
    // t goes from 0 to rows-2, so wall row index is t (0-based in wall buffer)
    dst_result[n] = wall[t * cols + n] + min;
}

